import { lazy } from "react";

function lazyTool(loader, exportName) {
  return lazy(() => loader().then((module) => ({ default: module[exportName] })));
}

function defineTool(config) {
  const required = ["slug", "name", "category", "shortDescription", "seoTitle", "seoDescription", "tags", "inputModel", "outputModel", "component"];
  for (const field of required) {
    if (config[field] === undefined || config[field] === null || config[field] === "") {
      throw new Error(`Tool registry is missing required field "${field}" for ${config.slug || config.name || "unknown tool"}.`);
    }
  }
  if (!Array.isArray(config.tags)) throw new Error(`Tool ${config.slug} must define tags as an array.`);
  return {
    aliases: [],
    synonyms: [],
    primaryKeyword: config.name,
    secondaryKeywords: config.tags,
    useCases: [],
    examples: [],
    faqs: [],
    trustNote: "",
    retainsData: false,
    supportsShareableUrl: false,
    ...config
  };
}

const names = {
  "text-data": "Text + Data",
  "file-tools": "File Tools",
  calculators: "Calculators",
  "dev-tech": "Dev + Tech",
  generators: "Generators",
  conversion: "Conversion",
  productivity: "Productivity",
  "comparison-decision": "Comparison + Decision"
};

function tool(category, config) {
  return defineTool({ category, categoryName: names[category], supportsLocalFiles: false, copyActions: ["Copy output"], ...config });
}

