const seenSlugs = new Set();
for (const entry of toolRegistry) {
  const values = [entry.slug, ...(entry.aliases || [])];
  for (const value of values) {
    if (seenSlugs.has(value)) {
      throw new Error(`Duplicate tool slug or alias detected: ${value}`);
    }
    seenSlugs.add(value);
  }
}
